sys_script_include.script:
var DecisionParser = Class.create();
DecisionParser.prototype = {
    _decision: null,
    _entries: {},

    initialize: function(decision_sys_id) {
        this._decision = decision_sys_id;
    },

    getEntries: function(includeDefault = false) {
        var dt = new sn_dt.DecisionTableAPI();
        var questions = dt.getQuestions(this._decision);
        return this._parseQuestions(questions, includeDefault);
    },

    _parseQuestions: function(questions, includeDefault) {
        var objects = [];
        questions = questions.result;

        // filter out the default answer
        if (!includeDefault) questions = questions.filter(e => defaultAnswer == false);

        questions.forEach(function(e) {
            objects.push(this._parseQuestion(e));
        });

        // todo mark invalid if...

        return objects;
    },

    _parseQuestion: function(question) {
        var obj = {
            "valid": true,
            "u_location": "",
            "message": "",
            "answer": {
                "label": "",
                "value": ""
            }

        };


        return obj;
    },


    // _parse: function(questions, includeDefault) {
    //     return ['Bob'];
    // },

    type: 'DecisionParser'
};
